const PARAMS = {
  primaryColor: "#3498db", // type: color
  secondaryColor: "#2ecc71", // type: color
  speed: 1.0, // type: range, min: 0.1, max: 3.0
  text: "한국어 ＠＃＄％＾ & < > \" \ / \\ \n \t", // type: text
  fontSize: 80, // type: range, min: 20, max: 200, unit: px
  visible: true, // type: boolean
  animStyle: "spring", // type: select, options: bounce|spring|linear
  icon: "Sparkles", // type: icon
} as const;

export const GeneratedAsset = ({
  primaryColor = PARAMS.primaryColor,
  secondaryColor = PARAMS.secondaryColor,
  speed = PARAMS.speed,
  text = PARAMS.text,
  fontSize = PARAMS.fontSize,
  visible = PARAMS.visible,
  animStyle = PARAMS.animStyle,
  icon = PARAMS.icon
}: typeof PARAMS = PARAMS) => {
  const frame = useCurrentFrame();
  const { durationInFrames, fps, width, height } = useVideoConfig();

  const progress = spring({
    fps,
    frame,
    config: { damping: 200 * speed },
  });

  const opacity = interpolate(progress, [0, 1], [0, 1]);

  const Icon = lucide[icon] ?? lucide.Sparkles;

  return (
    <AbsoluteFill style={{ backgroundColor: 'transparent', alignItems: 'center', justifyContent: 'center' }}>
      {visible && (
        <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
          <Icon size={50} color={primaryColor} />
          <span
            style={{
              color: secondaryColor,
              fontSize,
              opacity,
              transition: `opacity ${1 / speed}s ${animStyle}`,
            }}
          >
            {text}
          </span>
        </div>
      )}
    </AbsoluteFill>
  );
};

